import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  PhotographIcon, 
  CalendarIcon, 
  UserGroupIcon, 
  AcademicCapIcon,
  HeartIcon,
  ShareIcon,
  SearchIcon,
  PlusIcon
} from '@heroicons/react/outline';
import { HeartIcon as HeartSolidIcon } from '@heroicons/react/solid';
import toast from 'react-hot-toast';

const Gallery = () => {
  const [activeCategory, setActiveCategory] = useState('all');
  const [images, setImages] = useState([]);
  const [albums, setAlbums] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [likedImages, setLikedImages] = useState(new Set());
  const { category } = useParams();

  useEffect(() => {
    if (category) {
      setActiveCategory(category);
    }
    fetchGalleryData();
  }, [category]);

  const fetchGalleryData = async () => {
    try {
      setLoading(true);

      // Fetch both images and albums
      const [imagesResponse, albumsResponse] = await Promise.all([
        fetch('/api/gallery'),
        fetch('/api/gallery/albums')
      ]);

      const imagesData = await imagesResponse.json();
      const albumsData = await albumsResponse.json();

      if (imagesData.success) {
        setImages(imagesData.data.images || []);
      }

      if (albumsData.success) {
        setAlbums(albumsData.data.albums || []);
      }
    } catch (error) {
      console.error('Error fetching gallery data:', error);
      toast.error('Failed to load gallery');
    } finally {
      setLoading(false);
    }
  };

  const categories = [
    { id: 'all', name: 'All Photos', icon: PhotographIcon },
    { id: 'campus', name: 'Campus', icon: AcademicCapIcon },
    { id: 'events', name: 'Events', icon: CalendarIcon },
    { id: 'alumni', name: 'Alumni', icon: UserGroupIcon },
    { id: 'faculty', name: 'Faculty', icon: AcademicCapIcon }
  ];

  const filteredImages = images.filter(image => {
    const matchesCategory = activeCategory === 'all' || image.category === activeCategory;
    const matchesSearch = image.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         image.description?.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const filteredAlbums = albums.filter(album => {
    const matchesCategory = activeCategory === 'all' || album.category === activeCategory;
    const matchesSearch = album.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         album.description?.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const handleLike = async (imageId) => {
    try {
      const newLikedImages = new Set(likedImages);

      if (likedImages.has(imageId)) {
        newLikedImages.delete(imageId);
        toast.success('Removed from favorites');
      } else {
        newLikedImages.add(imageId);
        toast.success('Added to favorites');
      }

      setLikedImages(newLikedImages);

      // Update like count on server
      await fetch(`/api/gallery/${imageId}/like`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
    } catch (error) {
      console.error('Error liking image:', error);
      toast.error('Failed to update favorite status');
    }
  };

  const handleShare = (item) => {
    const url = window.location.origin + `/gallery/${item._id || item.id}`;
    if (navigator.share) {
      navigator.share({
        title: item.title,
        text: item.description,
        url: url
      });
    } else {
      navigator.clipboard.writeText(url);
      toast.success('Link copied to clipboard!');
    }
  };

  const openImageModal = (image) => {
    window.open(image.url, '_blank');
  };

  const openAlbum = (album) => {
    // Navigate to album view or open album modal
    toast.success(`Opening album: ${album.title}`);
  };

  const handleUpload = () => {
    if (localStorage.getItem('token')) {
      toast.success('Upload feature coming soon!');
    } else {
      toast.error('Please login to upload images');
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-mvsr-600"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 pt-20">
      {/* Header */}
      <div className="bg-white shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl md:text-4xl font-bold text-gray-900">Gallery</h1>
              <p className="mt-1 text-sm text-gray-600">
                Explore memories from MVSR Engineering College
              </p>
            </div>

            {/* Search Bar */}
            <div className="relative">
              <input
                type="text"
                placeholder="Search images and albums..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-64 pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-mvsr-500 focus:border-transparent"
              />
              <SearchIcon className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
            </div>
          </div>
        </div>
      </div>

      {/* Category Tabs */}
      <div className="bg-white border-b">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex space-x-8">
            {categories.map((cat) => {
              const IconComponent = cat.icon;
              return (
                <button
                  key={cat.id}
                  onClick={() => setActiveCategory(cat.id)}
                  className={`py-4 px-1 border-b-2 font-medium text-sm flex items-center space-x-2 transition-colors ${
                    activeCategory === cat.id
                      ? 'border-mvsr-600 text-mvsr-600'
                      : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                  }`}
                >
                  <IconComponent className="h-5 w-5" />
                  <span>{cat.name}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Albums Section */}
        {filteredAlbums.length > 0 && (
          <div className="mb-12">
            <h2 className="text-2xl font-bold text-gray-900 mb-6">Albums</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredAlbums.map((album) => (
                <div
                  key={album.id}
                  onClick={() => openAlbum(album)}
                  className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow duration-300 cursor-pointer"
                >
                  <div className="relative">
                    <img
                      src={album.coverImage}
                      alt={album.title}
                      className="w-full h-48 object-cover"
                    />
                    {album.featured && (
                      <div className="absolute top-2 right-2 bg-mvsr-600 text-white px-2 py-1 rounded text-xs font-medium">
                        Featured
                      </div>
                    )}
                  </div>
                  <div className="p-4">
                    <h3 className="font-medium text-gray-900 truncate">{album.title}</h3>
                    <p className="text-sm text-gray-600 truncate mb-2">{album.description}</p>
                    <div className="flex items-center justify-between text-sm text-gray-500">
                      <span className="flex items-center">
                        <PhotographIcon className="h-4 w-4 mr-1" />
                        {album.photos} photos
                      </span>
                      <span>{album.date}</span>
                    </div>
                    {album.highlights && (
                      <div className="mt-2 flex flex-wrap gap-1">
                        {album.highlights.slice(0, 2).map((highlight, index) => (
                          <span
                            key={index}
                            className="inline-block bg-gray-100 text-gray-700 text-xs px-2 py-1 rounded"
                          >
                            {highlight}
                          </span>
                        ))}
                        {album.highlights.length > 2 && (
                          <span className="inline-block bg-gray-100 text-gray-700 text-xs px-2 py-1 rounded">
                            +{album.highlights.length - 2} more
                          </span>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Images Grid */}
        {filteredImages.length > 0 && (
          <div>
            <h2 className="text-2xl font-bold text-gray-900 mb-6">Recent Photos</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
              {filteredImages.map((image) => (
                <div
                  key={image._id}
                  className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow duration-300"
                >
                  {/* Image */}
                  <div className="relative group cursor-pointer" onClick={() => openImageModal(image)}>
                    <img
                      src={image.thumbnail || image.url}
                      alt={image.title}
                      className="w-full h-48 object-cover"
                    />

                    {/* Overlay on hover */}
                    <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-50 transition-opacity duration-300 flex items-center justify-center">
                      <SearchIcon className="h-8 w-8 text-white opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                    </div>
                  </div>

                  {/* Image Info */}
                  <div className="p-4">
                    <h3 className="font-medium text-gray-900 truncate">{image.title}</h3>
                    <p className="text-sm text-gray-600 truncate">{image.description}</p>

                    <div className="mt-3 flex items-center justify-between">
                      <div className="flex items-center space-x-4 text-sm text-gray-500">
                        <span className="flex items-center">
                          <HeartIcon className="h-4 w-4 mr-1" />
                          {image.likes || 0}
                        </span>
                        <span>{new Date(image.createdAt).toLocaleDateString()}</span>
                      </div>

                      {/* Action Buttons */}
                      <div className="flex items-center space-x-2">
                        <button
                          onClick={() => handleLike(image._id)}
                          className="p-2 rounded-full hover:bg-gray-100 transition-colors"
                        >
                          {likedImages.has(image._id) ? (
                            <HeartSolidIcon className="h-5 w-5 text-red-500" />
                          ) : (
                            <HeartIcon className="h-5 w-5 text-gray-400 hover:text-red-500" />
                          )}
                        </button>

                        <button
                          onClick={() => handleShare(image)}
                          className="p-2 rounded-full hover:bg-gray-100 transition-colors"
                        >
                          <ShareIcon className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Empty State */}
        {filteredImages.length === 0 && filteredAlbums.length === 0 && (
          <div className="text-center py-12">
            <PhotographIcon className="mx-auto h-12 w-12 text-gray-400" />
            <h3 className="mt-2 text-sm font-medium text-gray-900">No images found</h3>
            <p className="mt-1 text-sm text-gray-500">
              {searchTerm ? 'Try adjusting your search terms' : 'No images in this category yet'}
            </p>
          </div>
        )}
      </div>

      {/* Upload Button */}
      <button
        onClick={handleUpload}
        className="fixed bottom-8 right-8 bg-mvsr-600 text-white rounded-full p-4 shadow-lg hover:bg-mvsr-700 transition-colors"
      >
        <PlusIcon className="h-6 w-6" />
      </button>
    </div>
  );
};

export default Gallery;
